public static async Task<bool> HealWanderer()
{
    var tonberryWanderer = 1650;

    if (CommonBehaviors.IsLoading || QuestLogManager.InCutscene)
    {
        return false;
    }

    LlamaLibrary.Logging.LLogger Logging = new("The Beast Within:", Colors.Aquamarine);
    var tonberryToHeal = GameObjectManager.GetObjectsOfType<BattleCharacter>()
        .OrderBy(bc => bc.Distance()).FirstOrDefault(bc => bc.InLineOfSight() && bc.NpcId == tonberryWanderer && !bc.CanAttack && bc.IsVisible && bc.IsTargetable);

    if (tonberryToHeal != null && tonberryToHeal.IsValid)
    {
        Logging.Information($"Found {tonberryToHeal.EnglishName}");
        ActionManager.DoAction("Physick", tonberryToHeal);
        await Coroutine.Wait(5000, () => !Core.Me.IsCasting);
    }

    return false;
}

Logging.Write("Commencing duty.");
uint[] npcIds = { 1021261, 2006316 };
var dutyNpc = GameObjectManager.GameObjects.Where(r => r.IsTargetable && npcIds.Contains(r.NpcId)).OrderBy(r => r.Distance()).FirstOrDefault();

while (Core.Me.Location.Distance2D(dutyNpc.Location) > 1.5f)
{
	await Coroutine.Yield();
	Navigator.PlayerMover.MoveTowards(dutyNpc.Location);
}

Navigator.PlayerMover.MoveStop();
dutyNpc.Interact();
await Coroutine.Wait(5000, () => Talk.DialogOpen || DifficultySelectYesNo.IsOpen || SelectYesno.IsOpen);

while (!(DifficultySelectYesNo.IsOpen || SelectYesno.IsOpen))
{
	Talk.Next();
	await Coroutine.Yield();
}

await Coroutine.Wait(5000, () => DifficultySelectYesNo.IsOpen || SelectYesno.IsOpen);

if (DifficultySelectYesNo.IsOpen)
{
	DifficultySelectYesNo.Proceed(2);
}
else if (SelectYesno.IsOpen)
{
	SelectYesno.Yes();
}
else
{
	Logging.Write("Duty window didn't open.");
	TreeRoot.Stop();
}

await Coroutine.Wait(2000, () => CommonBehaviors.IsLoading);
await Coroutine.Wait(-1, () => !CommonBehaviors.IsLoading);

while (ff14bot.Managers.QuestLogManager.InCutscene)
{
	ff14bot.RemoteAgents.AgentCutScene.Instance.PromptSkip();
	if (ff14bot.RemoteAgents.AgentCutScene.Instance.CanSkip && SelectString.IsOpen) { SelectString.ClickSlot(0); }
	if (Talk.DialogOpen) { Talk.Next(); }
	await Coroutine.Yield();
}

await Coroutine.Wait(2000, () => CommonBehaviors.IsLoading);
await Coroutine.Wait(-1, () => !CommonBehaviors.IsLoading);
await Coroutine.Wait(10000, () => !Core.Me.HasAura(1268));
Logging.Write("Duty commenced.");
await Coroutine.Sleep(1500);

foreach(BagSlot slot in InventoryManager.FilledInventoryAndArmory)
{
	BagSlot EquipSlot1 = InventoryManager.GetBagByInventoryBagId(ff14bot.Enums.InventoryBagId.EquippedItems)[ff14bot.Enums.EquipmentSlot.Head];
	BagSlot EquipSlot3 = InventoryManager.GetBagByInventoryBagId(ff14bot.Enums.InventoryBagId.EquippedItems)[ff14bot.Enums.EquipmentSlot.Hands];
	BagSlot EquipSlot5 = InventoryManager.GetBagByInventoryBagId(ff14bot.Enums.InventoryBagId.EquippedItems)[ff14bot.Enums.EquipmentSlot.Legs];
	BagSlot EquipSlot6 = InventoryManager.GetBagByInventoryBagId(ff14bot.Enums.InventoryBagId.EquippedItems)[ff14bot.Enums.EquipmentSlot.Feet];

	if(slot.RawItemId == 2905)
	{
		slot.Move(EquipSlot1);
		await Coroutine.Sleep(2000);
	}

	if(slot.RawItemId == 3689)
	{
		slot.Move(EquipSlot3);
		await Coroutine.Sleep(2000);
	}

	if(slot.RawItemId == 3466)
	{
		slot.Move(EquipSlot5);
		await Coroutine.Sleep(2000);
	}

	if(slot.RawItemId == 3897)
	{
		slot.Move(EquipSlot6);
		await Coroutine.Sleep(2000);
	}
}


